import{_ as u,C as a,o as r,c as q,j as i,a as o,E as e,a3 as h}from"./chunks/framework.CVjg771q.js";const y=JSON.parse('{"title":"文昌帝君阴骘文","description":"一篇从存心与阴德落到日用善行的劝善短文。","frontmatter":{"title":"文昌帝君阴骘文","description":"一篇从存心与阴德落到日用善行的劝善短文。","category":"guide","aliases":["阴骘文","文昌帝君阴骘文","wenchang yinzhiwen"],"source":["文昌帝君阴骘文"]},"headers":[],"relativePath":"daoism/daoist-classics/wenchang-yinzhiwen.md","filePath":"daoism/daoist-classics/wenchang-yinzhiwen.md","lastUpdated":1782750099000}'),d={name:"daoism/daoist-classics/wenchang-yinzhiwen.md"};function m(s,t,c,g,b,_){const n=a("DaoReadingPrelude"),l=a("DaoOriginalReading"),p=a("DaoKeywordCards");return r(),q("div",null,[t[0]||(t[0]=i("h1",{id:"文昌帝君阴骘文",tabindex:"-1"},[o("文昌帝君阴骘文 "),i("a",{class:"header-anchor",href:"#文昌帝君阴骘文","aria-label":'Permalink to "文昌帝君阴骘文"'},"​")],-1)),e(n,{title:"先从帝君自述看何为阴骘",summary:"文昌帝君阴骘文与太上感应篇气质相近，但起手方式不同——不是先列戒条，而是先拿自己如何存心、如何做人来立一个样子。全篇从存心到善行，从日用小事到济人利物，最后八字收全篇：诸恶莫作，众善奉行。",points:[{label:"先立",text:"帝君以自述开篇——十七世守一方向，不是一时作秀。"},{label:"再展",text:"善从存心流出，散为日用善行、待人分寸、济物实事。"},{label:"后收",text:"八字收全篇，吉神福报不是交易，是自然而来。"}],hint:"建议先通读一遍原文感受气息，再进入逐句解读。"}),t[1]||(t[1]=i("h2",{id:"【原典层】原文",tabindex:"-1"},[o("【原典层】原文 "),i("a",{class:"header-anchor",href:"#【原典层】原文","aria-label":'Permalink to "【原典层】原文"'},"​")],-1)),e(l,{paragraphs:["帝君曰：","吾一十七世为士大夫身，","未尝虐民酷吏；","救人之难，济人之急；","悯人之孤，容人之过。","广行阴骘，上格苍穹。","人能如我存心，天必锡汝以福。","于是训于人曰：","昔于公治狱，大兴驷马之门；","窦氏济人，高折五枝之桂。","救蚁，中状元之选；","埋蛇，享宰相之荣。","欲广福田，须凭心地。","行时时之方便，作种种之阴功。","利物利人，修善修福。","正直代天行化，慈祥为国救民。","存平等心，扩宽大量。","忠主孝亲，敬兄信友。","和睦夫妇，教训子孙，","毋慢师长，毋侮圣言。","或奉真朝斗，或拜佛念经。","报答四恩，广行三教。","谈道义而化奸顽，讲经史而晓愚昧。","济急如济涸辙之鱼，","救危如救密罗之雀。","矜孤恤寡，敬老怜贫，","举善荐贤，饶人责己。","措衣食，周道路之饥寒；","施棺椁，免尸骸之暴露。","造漏泽之仁园，兴启蒙之义塾。","家富，提携亲戚；","岁饥，赈济邻朋。","斗秤须要公平，不可轻出重入；","奴仆待之宽恕，岂宜备责苛求。","印造经文，创修寺院。","舍药材以拯疾苦，施茶水以解渴烦。","点夜灯以照人行，造河船以济人渡。","或买物而放生，或持斋而戒杀。","举步常看虫蚁，禁火莫烧山林。","勿登山而网禽鸟，勿临水而毒鱼虾。","勿宰耕牛，勿弃字纸。","勿谋人之财产；勿妒人之技能；","勿淫人之妻女；勿唆人之争讼；","勿坏人之名利；勿破人之婚姻。","勿因私仇，使人兄弟不和；","勿因小利，使人父子不睦。","勿倚权势而辱善良，","勿恃富豪而欺穷困。","依本分而致谦恭，守规矩而遵法度。","谐和宗族，解释冤怨。","善人则亲近之，助德行于身心；","恶人则远避之，杜灾殃于眉睫。","常须隐恶扬善，不可口是心非。","恒记有益之语，罔谈非礼之言。","翦碍道之荆榛，除当途之瓦石。","修数百年崎岖之路，","造千万人来往之桥。","垂训以格人非，捐赀以成人美。","作事须循天理，出言要顺人心。","见先哲于羹墙，慎独知于衾影。","诸恶莫作，众善奉行。","永无恶曜加临，常有吉神拥护。","近报则在自己，远报则在儿孙。","百福骈臻，千祥云集，","岂不从阴骘中得来者哉？"]}),t[2]||(t[2]=i("p",null,[i("img",{src:"https://www.fridolph.top/static/dao/yinzhiwen.png-minwebp.webp",alt:"文昌帝君阴骘文"})],-1)),t[3]||(t[3]=i("h2",{id:"【原典层】字词释义",tabindex:"-1"},[o("【原典层】字词释义 "),i("a",{class:"header-anchor",href:"#【原典层】字词释义","aria-label":'Permalink to "【原典层】字词释义"'},"​")],-1)),e(p,{title:"字词释义",items:[{term:"骘",pinyin:["zhì"],meaning:"阴骘，指不为人知的善行。"},{term:"悯",pinyin:["mǐn"],meaning:"哀怜，同情。"},{term:"锡",pinyin:["xī"],meaning:"古通赐，赐予之意。"},{term:"驷",pinyin:["sì"],meaning:"驷马，指四匹马拉的车，喻高门显达。"},{term:"窦",pinyin:["dòu"],meaning:"此处指窦禹钧，五子登科典故。"},{term:"毋",pinyin:["wú"],meaning:"不要，不可。"},{term:"涸",pinyin:["hé"],meaning:"涸辙，干涸的车辙沟，喻困境。"},{term:"辙",pinyin:["zhé"],meaning:"车轮压痕；涸辙之鱼喻急难。"},{term:"矜",pinyin:["jīn"],meaning:"怜悯，顾惜；非自矜之意。"},{term:"恤",pinyin:["xù"],meaning:"体恤，顾念，周全照应。"},{term:"寡",pinyin:["guǎ"],meaning:"寡居，失所恃，生活单薄者。"},{term:"饶",pinyin:["ráo"],meaning:"饶人，宽容、放人一步。"},{term:"椁",pinyin:["guǒ"],meaning:"棺椁，外棺与内棺，泛指葬具。"},{term:"恃",pinyin:["shì"],meaning:"倚仗，依靠。勿恃富豪而欺穷困。"},{term:"殃",pinyin:["yāng"],meaning:"灾殃，祸患，灾害。"},{term:"罔",pinyin:["wǎng"],meaning:"罔谈，不要谈、不去谈。"},{term:"翦",pinyin:["jiǎn"],meaning:"翦除，剪除、清除之意。"},{term:"榛",pinyin:["zhēn"],meaning:"荆榛，泛指丛生灌木杂草。"},{term:"赀",pinyin:["zī"],meaning:"捐赀，捐出财物。"},{term:"羹",pinyin:["gēng"],meaning:"羹墙，典出思慕至深时于汤羹墙壁亦见其人。"},{term:"衾",pinyin:["qīn"],meaning:"衾影，被子和影子；独寝不愧衾，喻慎独。"},{term:"曜",pinyin:["yào"],meaning:"恶曜，不吉之星象，喻灾祸。"},{term:"骈",pinyin:["pián"],meaning:"骈臻，并至、齐来。"},{term:"臻",pinyin:["zhēn"],meaning:"达到，到来。百福骈臻。"},{term:"阴骘",pinyin:["yīn","zhì"],meaning:"不为人知、不求回报的善行。骘本义为定，阴骘即暗中安定的力量。",context:"全篇总纲——善不在热闹处，而在无人处的真心。"},{term:"苍穹",pinyin:["cāng","qióng"],meaning:"苍天、上天。穹指穹窿，高远不可及。",context:"上格苍穹，即至诚之善能上达于天。"},{term:"存心",pinyin:["cún","xīn"],meaning:"守住、安住这颗心。不是刻意储存，而是本心不散失。",context:"人能如我存心——帝君自述：我无非是守住了这颗心。"},{term:"福田",pinyin:["fú","tián"],meaning:"比喻善行如良田，能生福果。",context:"欲广福田，须凭心地——心地是土壤，福田是收成。"},{term:"阴功",pinyin:["yīn","gōng"],meaning:"不张扬的善功。阴指方式（不显），功指实效（不止于心念）。",context:"与阴骘互通，偏重持续的善行积累对气质的影响。"},{term:"驷马",pinyin:["sì","mǎ"],meaning:"四匹马拉的车，古代高官显达的象征。",context:"于公治狱不冤人，后家门显达——守公道亦是积德。"},{term:"奸顽",pinyin:["jiān","wán"],meaning:"奸指心术偏、顺私欲而行；顽指心硬、不肯转。",context:"谈道义而化奸顽——化比惩更深，相信人可转回来。"},{term:"愚昧",pinyin:["yú","mèi"],meaning:"偏重蒙蔽之意，不是天生低劣，而是眼前被遮、心未亮。",context:"讲经史而晓愚昧——用有光的东西去照。"},{term:"涸辙之鱼",pinyin:["hé","zhé","zhī","yú"],meaning:"干涸车辙中的鱼，差一点水就能续命，喻急迫困难。",context:"济急如济之——那一点及时的水，能让人重新往活路去。"},{term:"密罗之雀",pinyin:["mì","luó","zhī","què"],meaning:"落入密网的鸟雀，越挣越紧，靠自己已难脱身。",context:"救危如救之——需要用救的方式，先把人从险处解出来。"},{term:"矜孤恤寡",pinyin:["jīn","gū","xù","guǎ"],meaning:"矜为怜惜而动心，恤为体察而周全，孤寡皆为失所恃之人。",context:"三字分寸不同——矜是心先触动，恤是落到行动周全。"},{term:"举善荐贤",pinyin:["jǔ","shàn","jiàn","xián"],meaning:"举是推出来不埋没，荐是托上去成全。",context:"不仅认出善，更要敢承认、敢靠近、舍得推出来。"},{term:"饶人责己",pinyin:["ráo","rén","zé","jǐ"],meaning:"饶是收手留余地，责己偏自照而非自罚。",context:"饶人最后也是饶自己——不松的心先困住自己。"},{term:"棺椁",pinyin:["guān","guǒ"],meaning:"棺为内棺，椁为外棺，泛指葬具，代表死者最后的安放与体面。",context:"施之免暴露——死者已不能回应，仍愿给他最后遮蔽。"},{term:"漏泽之仁园",pinyin:["lòu","zé","zhī","rén","yuán"],meaning:"为无主、无依、无葬者所设的公共归处。仁园非冷墓地，有人道温度。",context:"善到深处，不是一次施舍，而是建起能长期承接人的地方。"},{term:"启蒙之义塾",pinyin:["qǐ","méng","zhī","yì","shú"],meaning:"义塾是不为利而为人的学塾，启蒙不只是识字，更是让人看见世界。",context:"兴之一字与造仁园呼应——替后来者开门路，让好事持续发生。"},{term:"羹墙",pinyin:["gēng","qiáng"],meaning:"典出尧舜——思慕至深，在汤羹中见其人、在墙壁上见其人。",context:"见先哲于羹墙——先哲无处不在，天理时时在照。"},{term:"衾影",pinyin:["qīn","yǐng"],meaning:"衾为被子，影为影子。独立不惭影，独寝不愧衾——独处时最后的见证。",context:"慎独知于衾影——没人时，自己就是那个看着自己的人。"},{term:"四恩",pinyin:["sì","ēn"],meaning:"广义指天地、父母、师长、众生之恩。具体名单不必扣死，重在记得自己不是凭空活着。",context:"报答四恩——先记得受过什么，再拿行动回过去。"},{term:"三教",pinyin:["sān","jiào"],meaning:"此处指儒、释、道。但重点不在哪家高，而在广行二字。",context:"广行三教——心量要广，好的东西愿它传得更远。"},{term:"骈臻",pinyin:["pián","zhēn"],meaning:"骈是并、齐之意，臻是到来。百福骈臻即各种福一起到来。",context:"千祥云集，岂不从阴骘中得来者哉——全文收束。"}]}),t[4]||(t[4]=h("",104))])}const f=u(d,[["render",m]]);export{y as __pageData,f as default};
